using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private PriceCalculator _calculator = null!;

    [TestInitialize]
    public void Setup() => _calculator = new PriceCalculator();

    // ───────────────────────────────────────────────
    //  CalculateTotal – DataRow (compile-time constants)
    // ───────────────────────────────────────────────

    [TestMethod]
    [DataRow(10.00, 1, 0.0,  10.00,  DisplayName = "Single item, no tax")]
    [DataRow(10.00, 5, 0.0,  50.00,  DisplayName = "Multiple items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00,  DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 3, 0.08, 82.62,  DisplayName = "Fractional price, 8% tax")]
    [DataRow(0.00,  5, 0.10, 0.00,   DisplayName = "Zero unit price")]
    [DataRow(10.00, 0, 0.10, 0.00,   DisplayName = "Zero quantity")]
    [DataRow(99.99, 1, 1.0,  199.98, DisplayName = "100% tax rate")]
    public void CalculateTotal_ValidInputs_ReturnsExpected(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    // ───────────────────────────────────────────────
    //  CalculateTotal – DynamicData (complex / edge cases)
    // ───────────────────────────────────────────────

    public static IEnumerable<object[]> InvalidCalculateTotalInputs
    {
        get
        {
            yield return new object[] { -1m, 1, 0.1m, "unitPrice", "Negative unit price" };
            yield return new object[] { 10m, -1, 0.1m, "quantity", "Negative quantity" };
            yield return new object[] { 10m, 1, -0.01m, "taxRate", "Negative tax rate" };
            yield return new object[] { 10m, 1, 1.01m, "taxRate", "Tax rate above 1" };
        }
    }

    [TestMethod]
    [DynamicData(nameof(InvalidCalculateTotalInputs), DynamicDataDisplayName = nameof(GetCustomDisplayName))]
    public void CalculateTotal_InvalidInputs_ThrowsArgumentOutOfRange(
        decimal unitPrice, int quantity, decimal taxRate, string expectedParam, string _)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(unitPrice, quantity, taxRate));

        Assert.AreEqual(expectedParam, ex.ParamName);
    }

    // ───────────────────────────────────────────────
    //  ApplyDiscount – DataRow
    // ───────────────────────────────────────────────

    [TestMethod]
    [DataRow(100.00, 0.0,   100.00, DisplayName = "0% discount – full price")]
    [DataRow(100.00, 10.0,  90.00,  DisplayName = "10% discount")]
    [DataRow(100.00, 50.0,  50.00,  DisplayName = "50% discount")]
    [DataRow(100.00, 100.0, 0.00,   DisplayName = "100% discount – free")]
    [DataRow(49.99,  25.0,  37.4925, DisplayName = "Fractional result")]
    [DataRow(0.00,   50.0,  0.00,   DisplayName = "Zero price with discount")]
    public void ApplyDiscount_ValidInputs_ReturnsExpected(
        double price, double discountPercent, double expected)
    {
        var result = _calculator.ApplyDiscount((decimal)price, (decimal)discountPercent);

        Assert.AreEqual((decimal)expected, result);
    }

    // ───────────────────────────────────────────────
    //  ApplyDiscount – DynamicData (boundary violations)
    // ───────────────────────────────────────────────

    public static IEnumerable<object[]> InvalidDiscountInputs
    {
        get
        {
            yield return new object[] { 100m, -1m, "Discount below 0" };
            yield return new object[] { 100m, 100.01m, "Discount above 100" };
            yield return new object[] { 50m, -0.01m, "Slightly negative discount" };
        }
    }

    [TestMethod]
    [DynamicData(nameof(InvalidDiscountInputs), DynamicDataDisplayName = nameof(GetCustomDisplayName))]
    public void ApplyDiscount_InvalidDiscount_ThrowsArgumentOutOfRange(
        decimal price, decimal discountPercent, string _)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(price, discountPercent));

        Assert.AreEqual("discountPercent", ex.ParamName);
    }

    // ───────────────────────────────────────────────
    //  Shared display-name resolver for DynamicData
    // ───────────────────────────────────────────────

    public static string GetCustomDisplayName(MethodInfo method, object[] data) =>
        $"{method.Name} – {data[^1]}";
}

